#include <stdio.h>
#include <stdlib.h>
#define MAXN 30000

int** createMatrix(int n) {
    int** matrix = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        matrix[i] = (int*)malloc(n * sizeof(int));
    }
    return matrix;
}

void freeMatrix(int** matrix, int n) {
    for (int i = 0; i < n; i++) {
        free(matrix[i]);
    }
    free(matrix);
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int* a = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &a[i]);
        }
        int** matrix = createMatrix(n);
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                matrix[i][j] = a[(i + j) % n];
            }
        }
        int rank = 0;
        for (int i = 0; i < n; i++) {
            int maxRow = i;
            for (int j = i + 1; j < n; j++) {
                if (abs(matrix[j][i]) > abs(matrix[maxRow][i])) {
                    maxRow = j;
                }
            }
            if (maxRow != i) {
                int* temp = matrix[i];
                matrix[i] = matrix[maxRow];
                matrix[maxRow] = temp;
            }
            if (matrix[i][i] != 0) {
                rank++;
                for (int j = i + 1; j < n; j++) {
                    int factor = matrix[j][i] / matrix[i][i];
                    for (int k = i; k < n; k++) {
                        matrix[j][k] -= factor * matrix[i][k];
                    }
                }
            }
        }
        if (rank < n) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
        freeMatrix(matrix, n);
        free(a);
    }
    return 0;
}

